 1→/**
 2→ * `arraySymmetricDifference` takes in two arrays and returns only the elements not in common between the two arrays.
 3→ * @param a - The first array
 4→ * @param b - The second array
 5→ * @returns The elements not in common between the two arrays
 6→ * @example arraySymmetricDifference([1, 2, 3], [2, 3, 4]) // [1, 4]
 7→ */
 8→export const arraySymmetricDifference = <T>(a: T[], b: T[]) => {
 9→  if (typeof a[0] === "object" || typeof b[0] === "object") {
10→    throw new TypeError("arraySymmetricDifference does not support objects");
11→  }
12→  const setA = new Set(a);
13→  const setB = new Set(b);
14→  const difference = Array.from(
15→    new Set(a.concat(b).filter((x) => !setA.has(x) || !setB.has(x))),
16→  );
17→
18→  return difference;
19→};
20→
21→/**
22→ * `arraySetDifference` returns the elements in a that are not in b
23→ * @param a - The first array
24→ * @param b - The second array
25→ * @returns The elements in a that are not in b
26→ * @example arraySetDifference([1, 2, 3], [2, 3, 4]) // [1]
27→ */
28→export const arraySetDifference = <T>(a: T[], b: T[]) => {
29→  if (typeof a[0] === "object" || typeof b[0] === "object") {
30→    throw new TypeError("arraySetDifference does not support objects");
31→  }
32→  const setA = new Set(a);
33→  const setB = new Set(b);
34→  const difference = Array.from(setA).filter((x) => !setB.has(x));
35→  return difference;
36→};
37→
38→/**
39→ * `conditionalToArray` takes in a generic value and transforms it into an array if shouldBeArray is true.
40→ * The value remains unchanged if it is already an array, or if shouldBeArray is false.
41→ * @param value - The value to be transformed
42→ * @param shouldBeArray - A boolean indicating whether or not the value should be transformed into an array
43→ * @returns The transformed value
44→ */
45→export const conditionalToArray = <T>(
46→  value: T | T[],
47→  shouldBeArray: boolean,
48→): T[] => {
49→  if (shouldBeArray) {
50→    return Array.isArray(value) ? value : [value];
51→  }
52→  return value as T[];
53→};
54→

