 3→/**
 4→ * getUserStagingHeader generates the correct headers for the Evergreen-Multi staging backend to correctly route requests.
 5→ * @returns - an object with a key-value pair if the headers should be applied, and an empty object if not.
 6→ */
 7→export const getUserStagingHeader = (): {
 8→  "X-Evergreen-Environment"?: string;
 9→} => {
10→  if (!isStaging()) {
11→    return {};
12→  }
