 19→}
 20→
 21→interface AccordionProps {
 22→  caretAlign?: AccordionCaretAlign;
 23→  caretIcon?: AccordionCaretIcon;
 24→  children: React.ReactNode;
 25→  className?: string;
 26→  "data-cy"?: string;
 27→  defaultOpen?: boolean;
 28→  disableAnimations?: boolean;
 29→  onToggle?: (s: { isVisible: boolean }) => void;
 30→  open?: boolean;
 31→  subtitle?: React.ReactNode;
 32→  title: React.ReactNode;
 33→  titleTag?: React.FC;
 34→  toggledTitle?: React.ReactNode;
 35→  useIndent?: boolean;
 36→}
 37→
 38→const Accordion: React.FC<AccordionProps> = ({
 39→  caretAlign = AccordionCaretAlign.Center,
 40→  caretIcon = AccordionCaretIcon.Chevron,
 41→  children,
 42→  className,
 43→  "data-cy": dataCy,
 44→  defaultOpen = false,
 45→  disableAnimations = true,
 46→  onToggle = () => {},
 47→  open,
 48→  subtitle,
 49→  title,
 50→  titleTag,
 51→  toggledTitle,
 52→  useIndent = true,
 53→}) => {
 54→  const isControlled = open !== undefined;
 55→
 56→  const [uncontrolledAccordionOpen, setUncontrolledAccordionOpen] =
 57→    useState(defaultOpen);
 58→
 59→  // When controlled, use the open prop. Otherwise, use the uncontrolled state.
 60→  const accordionOpen = isControlled ? open : uncontrolledAccordionOpen;
 61→  const setAccordionOpen = isControlled
 62→    ? () => {}
 63→    : setUncontrolledAccordionOpen;
 64→
 65→  const TitleTag = titleTag ?? "span";
 66→  const titleToShow = toggledTitle && accordionOpen ? toggledTitle : title;
 67→  const titleComp = <TitleTag>{titleToShow}</TitleTag>;
 68→
 69→  const toggleAccordionHandler = () => {
 70→    onToggle({ isVisible: !accordionOpen });
 71→    setAccordionOpen(!accordionOpen);
 72→  };
 73→
 74→  return (
 75→    <div className={className} data-cy={dataCy}>
 76→      <AccordionToggle
 77→        data-cy="accordion-toggle"
 78→        onClick={toggleAccordionHandler}
 79→        role="button"
 80→      >
 81→        <AccordionIcon
 82→          aria-label="Accordion icon"
 83→          open={accordionOpen}
 84→          style={{ alignSelf: caretAlign }}
 85→        >
 86→          <Icon fill={gray.dark1} glyph={`${caretIcon}Right`} />
 87→        </AccordionIcon>
 88→        {titleComp}
 89→      </AccordionToggle>
 90→      {subtitle && <SubtitleContainer>{subtitle}</SubtitleContainer>}
 91→      <AnimatedAccordion
 92→        aria-expanded={accordionOpen}
 93→        data-cy="accordion-collapse-container"
 94→        disableAnimations={disableAnimations}
 95→        hide={!accordionOpen}
 96→      >
 97→        <ContentsContainer useIndent={useIndent}>{children}</ContentsContainer>
 98→      </AnimatedAccordion>
 99→    </div>
100→  );
101→};
