  display: flex;
  align-items: center;
  justify-content: center;
  position: absolute;
  bottom: 0;
  left: 16px;
  height: ${textInputHeight};
  color: ${gray.dark1};
  opacity: 0.5;
  pointer-events: none;
  white-space: nowrap;
  overflow: hidden;
  z-index: 2;
`;

