export const Default = meta.story({
  render: () => {
    return (
      <Popconfirm onConfirm={fn()} open setOpen={() => {}}>
        Are you sure you want to proceed?
      </Popconfirm>
    );
  },
  play: async ({ canvasElement }) => {
    const doc = canvasElement.ownerDocument;
    const confirmButton = doc.querySelector(
      'button[class*="Button"]',
