import { useState } from "react";
import { expect, fn } from "storybook/test";
import preview from "#.storybook/preview";
import { TreeSelect } from "./TreeSelect";
import type { TreeDataEntry } from "./TreeSelect";

const sampleData: TreeDataEntry[] = [
  {
    title: "All",
    value: "all",
    key: "all",
  },
  {
    title: "Fruits",
    value: "fruits",
    key: "fruits",
    children: [
      { title: "Apple", value: "apple", key: "apple" },
      { title: "Banana", value: "banana", key: "banana" },
    ],
  },
  {
    title: "Vegetables",
    value: "vegetables",
    key: "vegetables",
    children: [
      { title: "Carrot", value: "carrot", key: "carrot" },
      { title: "Broccoli", value: "broccoli", key: "broccoli" },
    ],
  },
];

const meta = preview.meta({
  component: TreeSelect,
  tags: ["ai-generated"],
});

export default meta;

export const NoneSelected = meta.story({
  render: () => {
    const [state, setState] = useState<string[]>([]);
    return (
      <TreeSelect state={state} tData={sampleData} onChange={setState} />
    );
  },
  play: async ({ canvas }) => {
    const checkboxes = canvas.getAllByRole("checkbox");
    await expect(checkboxes.length).toBeGreaterThanOrEqual(5);
  },
});

export const AllSelected = meta.story({
  render: () => {
    const [state, setState] = useState<string[]>([
      "all",
      "fruits",
      "apple",
      "banana",
      "vegetables",
      "carrot",
      "broccoli",
    ]);
    return (
      <TreeSelect state={state} tData={sampleData} onChange={setState} />
    );
  },
  play: async ({ canvas }) => {
    const allCheckbox = canvas.getAllByRole("checkbox")[0];
    await expect(allCheckbox).toBeChecked();
  },
});

