  render: () => {
    const [state, setState] = useState<string[]>([]);
    return (
      <TreeSelect state={state} tData={sampleData} onChange={setState} />
    );
  },
  play: async ({ canvas, userEvent }) => {
    const appleCheckbox = canvas.getByLabelText("Apple");
    await userEvent.click(appleCheckbox);
    await expect(appleCheckbox).toBeChecked();
  },
});

export const WithFilterControls = meta.story({
  render: () => {
    const [state, setState] = useState<string[]>(["apple"]);
