      <TreeSelect
        state={state}
        tData={sampleData}
        onChange={setState}
        onReset={fn()}
        onFilter={fn()}
      />
    );
  },
  play: async ({ canvas }) => {
    await expect(
      canvas.getByRole("button", { name: /filter/i }),
    ).toBeVisible();
  },
});

