import { expect } from "storybook/test";
import preview from "#.storybook/preview";
import LoginPage from "./index";

const meta = preview.meta({
  component: LoginPage,
  tags: ["ai-generated"],
  parameters: {
    layout: "fullscreen",
  },
});

export default meta;

export const Default = meta.story({
  args: {
    ignoreAuthCheck: true,
  },
  play: async ({ canvas }) => {
    await expect(canvas.getByLabelText("Username")).toBeVisible();
    await expect(canvas.getByLabelText("Password")).toBeVisible();
    await expect(
      canvas.getByRole("button", { name: /login/i }),
    ).toBeVisible();
  },
});

export const FilledForm = meta.story({
  args: {
    ignoreAuthCheck: true,
  },
  play: async ({ canvas, userEvent }) => {
    const usernameInput = canvas.getByLabelText("Username");
    const passwordInput = canvas.getByLabelText("Password");

    await userEvent.type(usernameInput, "admin");
    await userEvent.type(passwordInput, "password123");

    await expect(usernameInput).toHaveValue("admin");
    await expect(passwordInput).toHaveValue("password123");
  },
});

export const CssCheck = meta.story({
  args: {
    ignoreAuthCheck: true,
  },
  play: async ({ canvas }) => {
    const loginButton = canvas.getByRole("button", { name: /login/i });
    // LoginForm uses green.light3 as background-color
    // The button parent form should have the green background
    const form = loginButton.closest("form");
    await expect(form).not.toBeNull();
    const formBgColor = getComputedStyle(form!).backgroundColor;
    // green.light3 from @leafygreen-ui/palette is rgb(228, 244, 228)
    await expect(formBgColor).toBe("rgb(228, 244, 228)");
  },
});

