30→export const fetchWithRetry = <T = unknown>(
31→  url: string,
32→  options: RequestInit,
33→  retries: number = 3,
34→  backoff: number = 150,
35→): Promise<{ data: T }> =>
36→  new Promise((resolve, reject) => {
37→    const attemptFetch = (attempt: number): void => {
38→      fetch(url, options)
39→        .then((res) => {
40→          if (res.ok) {
41→            return res.json();
42→          }
43→          reject(
44→            new Error(getErrorMessage(res, "GET"), {
45→              cause: { message: res.statusText, statusCode: res.status },
46→            }),
47→          );
48→        })
49→        .then((data) => resolve(data))
50→        .catch((err) => {
51→          if (attempt <= retries) {
52→            setTimeout(() => attemptFetch(attempt + 1), backoff * attempt);
53→          } else {
54→            reject(err);
55→          }
56→        });
57→    };
58→    attemptFetch(1);
59→  });
