  7→  /** Report error as severe. This will cause an alert on our alerting infrastructure. Use this for critical errors. */
  8→  severe: () => void;
  9→  /** Report error as a warning. This will log the error to our infrastructure and will only alert if there is a spike. Use this for most errors. */
 10→  warning: () => void;
 11→}
 12→
 13→type ErrorMetadata = {
 14→  fingerprint?: ErrorInput["fingerprint"];
 15→  tags?: ErrorInput["tags"];
 16→  context?: ErrorInput["context"];
 17→};
 18→
 19→/**
 20→ * `reportError` is a utility function that reports an error to Sentry if Sentry is initialized.
 21→ * If Sentry is not initialized, it logs the error to the console.
 22→ * @param err - The error to report.
 23→ * @param param1 - The metadata for the error.
 24→ * @param param1.context - The context for the error.
 25→ * @param param1.fingerprint - The fingerprint for the error. This is used to group errors together.
 26→ * @param param1.tags - Any tags to attach to the error.
 27→ * @returns - An object with two functions: `severe` and `warning`. These functions report the error with different severities.
 28→ */
 29→const reportError = (
 30→  err: Error,
 31→  { context, fingerprint, tags }: ErrorMetadata = {},
 32→): reportErrorResult => {
 33→  if (!isInitialized()) {
 34→    return {
 35→      severe: () => {
 36→        console.error({ err, severity: "severe", context, fingerprint, tags });
 37→      },
 38→      warning: () => {
 39→        console.error({ err, severity: "warning", context, fingerprint, tags });
 40→      },
 41→    };
 42→  }
 43→
 44→  return {
 45→    severe: () => {
 46→      sentrySendError({
 47→        context,
 48→        err,
 49→        fingerprint,
 50→        severity: "error",
 51→        tags,
 52→      });
 53→    },
 54→    warning: () => {
 55→      sentrySendError({
 56→        context,
 57→        err,
 58→        fingerprint,
 59→        severity: "warning",
 60→        tags,
 61→      });
 62→    },
 63→  };
 64→};
 65→
 66→/**
 67→ * `leaveBreadcrumb` logs messages that are useful for debugging and will appear in the sentry timeline.
 68→ * @param message - The message to log.
 69→ * @param metadata - Any metadata to attach to the breadcrumb.
 70→ * @param type - The type of breadcrumb to log. This determines the icon that appears in the timeline.
 71→ */
 72→const leaveBreadcrumb = (
 73→  message: string,
 74→  metadata: Breadcrumb["data"],
 75→  type: SentryBreadcrumbTypes,
 76→) => {
 77→  if (!isInitialized()) {
 78→    console.debug({ message, metadata, type });
 79→  } else {
 80→    const bc: Breadcrumb = {
 81→      message,
 82→      data: validateMetadata(metadata, type),
 83→      // Divide date by 1000 because Sentry wants the timestamp in RFC 3339, or seconds (not milliseconds!) since the Unix epoch.
 84→      timestamp: new Date().getTime() / 1000,
 85→      type,
 86→    };
 87→    addBreadcrumb(bc);
 88→  }
 89→};
 90→
 91→/**
 92→ * `initializeErrorHandling` initializes error handling for the application.
 93→ * This function should be called once in the application's lifecycle.
 94→ * It initializes Sentry for production builds.
 95→ * @param options - The options for initializing error handling.
 96→ * @param options.isProductionBuild - Whether the application is a production build.
 97→ * @param options.sentryDSN - The Sentry DSN.
 98→ * @param options.environment - The environment the application is running in.
 99→ */
100→const initializeErrorHandling = ({
101→  environment,
102→  isProductionBuild,
103→  sentryDSN,
104→}: {
105→  isProductionBuild: boolean;
106→  sentryDSN: string;
107→  environment: string;
108→}) => {
109→  if (!isProductionBuild) {
110→    return;
111→  }
112→
113→  if (!isInitialized()) {
114→    initializeSentry({
115→      debug: !isProductionBuild,
116→      sentryDSN: sentryDSN,
117→      environment: environment,
118→    });
119→  }
120→};
121→
122→export {
123→  initializeErrorHandling,
124→  leaveBreadcrumb,
125→  reportError,
126→  SentryBreadcrumbTypes,
127→};
128→

