 5→/**
 6→ * `ErrorBoundary` is a wrapper around the `DefaultErrorBoundary` and `SentryErrorBoundary` components. It decides which
 7→ * error boundary to use based on whether Sentry is initialized or not.
 8→ * @param param0 - The props
 9→ * @param param0.children - The children
10→ * @param param0.homeURL - The home URL of the application.
11→ * @returns - The wrapped component.
12→ */
13→const ErrorBoundary: React.FC<{
14→  children: React.ReactNode;
15→  homeURL: string;
16→}> = ({ children, homeURL }) => {
17→  const shouldUseSentry = isInitialized();
18→
19→  if (shouldUseSentry) {
20→    return (
21→      <SentryErrorBoundary homeURL={homeURL}>{children}</SentryErrorBoundary>
22→    );
23→  }
24→  return (
25→    <DefaultErrorBoundary homeURL={homeURL}>{children}</DefaultErrorBoundary>
26→  );
27→};
28→
29→export default ErrorBoundary;
