 9→/**
10→ * DO NOT USE THIS COMPONENT DIRECTLY INSTEAD USE `ErrorBoundary`.
11→ *
12→ * `DefaultErrorBoundary` is a generic Error Boundary component. This component is used in development builds.
13→ * @param param0 - The props
14→ * @param param0.children - The children
15→ * @param param0.homeURL - The home URL of the application.
16→ * @returns - The wrapped component.
17→ */
18→class DefaultErrorBoundary extends Component<
19→  DefaultErrorBoundaryProps,
20→  { hasError: boolean }
21→> {
22→  constructor(props: DefaultErrorBoundaryProps) {
23→    super(props);
24→    this.state = { hasError: false };
25→  }
26→
27→  static getDerivedStateFromError() {
28→    // Update state so the next render will show the fallback UI.
29→    return { hasError: true };
30→  }
31→
32→  componentDidCatch(error: Error, errorInfo: React.ErrorInfo) {
33→    console.error({ error, errorInfo });
34→  }
35→
36→  render() {
37→    const { hasError } = this.state;
38→    if (hasError) {
39→      return <ErrorFallback homeURL={this.props.homeURL} />;
40→    }
41→    const { children } = this.props;
42→    return children;
43→  }
44→}
